import React, { useEffect, useRef, useState } from 'react';
import Background from './components/Background';
import Sidebar from './components/Sidebar';
import Home from './pages/Home';
import Projects from './pages/Projects';
import Experience from './pages/Experience';
import Contact from './pages/Contact';
import './App.css';

export default function App() {
  const [activePage, setActivePage] = useState('home');
  const [displayPage, setDisplayPage] = useState('home');
  const [transitioning, setTransitioning] = useState(false);
  const [entering, setEntering] = useState(false);
  const timers = useRef([]);

  useEffect(() => {
    return () => {
      timers.current.forEach((timer) => clearTimeout(timer));
    };
  }, []);

  const onNavigate = (newPage) => {
    if (newPage === activePage || transitioning) return;

    timers.current.forEach((timer) => clearTimeout(timer));
    timers.current = [];

    setTransitioning(true);

    timers.current.push(
      setTimeout(() => {
        setDisplayPage(newPage);
        setActivePage(newPage);
        setEntering(true);
      }, 280)
    );

    timers.current.push(
      setTimeout(() => {
        setTransitioning(false);
      }, 300)
    );

    timers.current.push(
      setTimeout(() => {
        setEntering(false);
      }, 320)
    );
  };

  const pageClassName = `page-wrapper ${transitioning ? 'page-exit' : 'page-enter'} ${
    !transitioning && entering ? 'page-enter-start' : ''
  }`;

  return (
    <div className="app-root">
      <Background />
      <Sidebar activePage={activePage} onNavigate={onNavigate} />

      <main className="main-area">
        <div className={pageClassName}>
          {displayPage === 'home' && <Home onNavigate={onNavigate} />}
          {displayPage === 'projects' && <Projects />}
          {displayPage === 'experience' && <Experience />}
          {displayPage === 'contact' && <Contact />}
        </div>
      </main>
    </div>
  );
}
